import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"개발 환경 설정하기","description":"Fabric을 이용하여 모드를 만들기 위해 개발 환경을 설정하는 방법에 대한 단계적 설명서입니다.","frontmatter":{"title":"개발 환경 설정하기","description":"Fabric을 이용하여 모드를 만들기 위해 개발 환경을 설정하는 방법에 대한 단계적 설명서입니다.","authors":["2xsaiko","andrew6rant","asiekierka","daomephsta","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","telepathicgrunt"],"authors-nogithub":["siglong"],"files":[]},"headers":[],"relativePath":"ko_kr/1.21.10/develop/getting-started/setting-up-a-development-environment.md","filePath":"versions/1.21.10/translated/ko_kr/develop/getting-started/setting-up-a-development-environment.md","lastUpdated":1766682904000}`);var o={name:`ko_kr/1.21.10/develop/getting-started/setting-up-a-development-environment.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">개발 환경 설정하기 <a class="header-anchor" href="#h1" aria-label="Permalink to “개발 환경 설정하기”">​</a></h1><p>Fabric으로 모드를 개발하려면, 먼저 개발 환경을 설정해야 합니다. 이 설명서는 JetBrains의 IntelliJ IDEA를 이용한 방법을 설명합니다.</p><h2 id="installing-jdk-21" tabindex="-1">JDK 21 설치 <a class="header-anchor" href="#installing-jdk-21" aria-label="Permalink to “JDK 21 설치”">​</a></h2><p>Minecraft 1.21.4의 모드를 개발하려면, JDK(Java Development Kit, Java 개발 키트) 21이상이 필요합니다.</p><p>Java 설치에 대한 자세한 방법은 <a href="./../../players/index">플레이어 설명서</a>를 참조하십시오.</p><h2 id="installing-intellij-idea" tabindex="-1">IntelliJ IDEA 설치 <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “IntelliJ IDEA 설치”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Eclipse나 Visual Studio Code처럼 다른 IDE를 사용할 수도 있지만, Fabric 문서의 모든 설명서는 IntelliJ IDEA를 예시로 사용하고 있습니다. 다른 IDE를 사용하는 경우 해당 IDE의 문서를 참조해야 합니다.</p></div><p>IntelliJ IDEA가 아직 설치되어 있지 않다면, <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">공식 웹사이트</a>에서 다운로드할 수 있습니다. 웹사이트에서 제공하는 운영 체제별 설치 과정을 따라주시기 바랍니다.</p><p>IntelliJ IDEA Community Edition은 무료 오픈소스로, Fabric 모딩에 권장하는 IDE입니다.</p><p>Community Edition을 찾으려면 페이지를 조금 내려야 할 수 있으며, 아래와 같이 표시됩니다.</p><p><img src="/assets/develop/getting-started/idea-community.png" alt="IntelliJ IDEA Community Edition 다운로드 프롬프트" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">IDEA 플러그인 다운로드 <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “IDEA 플러그인 다운로드”">​</a></h2><p>이 플러그인은 필수적이지는 않지만, Fabric 모딩을 훨씬 더 쉽게 만들기 때문에 설치를 고려하는 것이 좋습니다.</p><h3 id="minecraft-development" tabindex="-1">Minecraft Development <a class="header-anchor" href="#minecraft-development" aria-label="Permalink to “Minecraft Development”">​</a></h3><p>Minecraft Development 플러그인은 Fabric 모딩 지원을 제공하는 플러그인으로, 설치해야 할 가장 중요한 플러그인입니다.</p><p>IntelliJ IDEA를 열고, 네비게이션 바에서 <code>File &gt; Settings &gt; Plugins &gt; Marketplace 탭</code>으로 이동하여 <code>Minecraft Development</code>를 검색한 후, <code>Install</code> 버튼을 클릭하여 설치할 수 있습니다.</p><p>또는, <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">플러그인 페이지</a>에서 파일을 직접 다운로드하여 <code>File &gt; Settings &gt; Plugins &gt; Install Plugin From Disk</code>로 이동하여 설치할 수도 있습니다.</p>`,17)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};